// ── TTS_LANGS ───────────────────────────────────────────────────────
export const TTS_LANGS=['fr','en','es','it','de','pt','ar','zh','ja','ko','hi','tr','ru'];

// ── Translation functions ────────────────────────────────────────────

export function t(key){
  const langPack=UI_I18N[S.selectedUILanguage]||UI_I18N.en;
  const extra=UI_EXTRA_I18N[S.selectedUILanguage]||UI_EXTRA_I18N.en||{};
  const fb=UI_FALLBACK_TRANSLATIONS[key];
  const fallback=(fb&&(fb[S.selectedUILanguage]||fb.en))||'';
  return langPack[key]||extra[key]||fallback||UI_I18N.en[key]||(UI_EXTRA_I18N.en&&UI_EXTRA_I18N.en[key])||key;
}
export function ts(text){
  if(!text)return text;
  const mapFr={
    'Connected':'connected',
    'Partenaire connecté !':'partnerConnected',
    'Disconnected':'disconnected',
    'Partenaire déconnecté':'partnerDisconnected',
    'Error':'error',
    'Waiting for partner…':'waitingForPartner',
    'Waiting…':'waitingOverlayTitle',
    'Share code: ':'waitingOverlayMessage',
    'Entre un code':'joinCodeMissing',
    'Connecting…':'connection',
    'Looking for ':'searching',
    'Session introuvable.':'sessionNotFound',
    'Slow connection':'connectionSlow',
    'Code unavailable':'codeUnavailable',
    'Code copié ✅':'codeCopied',
    'Link unavailable':'linkUnavailable',
    'Lien copié ✅':'linkCopied',
    'Copie impossible':'copyFailed',
    'Texte copié, colle-le dans WeChat':'shareTextCopied',
    'Texte copié ✅':'shareTextCopied',
    'Share unavailable':'shareUnavailable',
    'Code prérempli : ':'joinCodePrefilled',
  };
  const key=mapFr[text];
  if(key)return t(key);
  if(text.startsWith('Error:'))return t('error')+text.slice('Error'.length);
  if(text.startsWith('Code prérempli : '))return t('joinCodePrefilled')+': '+text.slice('Code prérempli : '.length);
  return text;
}
export function getEmotionLabel(key){
  const map={
    neutral:{fr:'Neutre',en:'Neutral',es:'Neutral',it:'Neutro',zh:'中性',ar:'محايد',de:'Neutral',pt:'Neutro',ja:'ニュートラル',ko:'중립',hi:'तटस्थ'},
    excited:{fr:'Excité',en:'Excited',es:'Emocionado',it:'Eccitato',zh:'兴奋',ar:'متحمس',de:'Aufgeregt',pt:'Animado',ja:'興奮',ko:'흥분',hi:'उत्साहित'},
    sad:{fr:'Triste',en:'Sad',es:'Triste',it:'Triste',zh:'悲伤',ar:'حزين',de:'Traurig',pt:'Triste',ja:'悲しい',ko:'슬픔',hi:'उदास'},
    angry:{fr:'En colère',en:'Angry',es:'Enfadado',it:'Arrabbiato',zh:'愤怒',ar:'غاضب',de:'Wütend',pt:'Com raiva',ja:'怒り',ko:'화남',hi:'गुस्सा'},
    whisper:{fr:'Chuchoté',en:'Whisper',es:'Susurrado',it:'Sussurrato',zh:'耳语',ar:'هامس',de:'Flüsternd',pt:'Sussurrado',ja:'ささやき',ko:'속삭임',hi:'फुसफुसाहट'},
  };
  const row=map[key];
  if(!row)return key;
  return row[S.selectedUILanguage]||row.en||row.fr||key;
}
export function setTextById(id,key){
  const el=document.getElementById(id);
  if(el)el.textContent=t(key);
}
function setCineTitleById(id,key){
  const el=document.getElementById(id);
  if(!el||!el.closest('.cine-screen'))return setTextById(id,key);
  const txt=t(key).replace(/\.\s*$/,'');
  const words=txt.split(' ');
  const mid=Math.ceil(words.length/2);
  el.innerHTML=words.slice(0,mid).join(' ')+'<br>'+words.slice(mid).join(' ')+'<span class="cine-dot">.</span>';
}

export function initSiteLanguageSelect(){
  const select=document.getElementById('siteLanguageSelect');
  if(!select)return;
  select.innerHTML='';
  UI_LANGUAGES.forEach(l=>{
    const opt=document.createElement('option');
    opt.value=l.id;
    opt.textContent=(l.flag?l.flag+' ':'')+l.label;
    if(l.id===S.selectedUILanguage)opt.selected=true;
    select.appendChild(opt);
  });
  syncLangSelectDisplay(select);
}
export function syncLangSelectDisplay(select){
  if(!select)select=document.getElementById('siteLanguageSelect');
  if(!select)return;
  Array.from(select.options).forEach(opt=>{
    const lang=UI_LANGUAGES.find(l=>l.id===opt.value);
    if(!lang)return;
    opt.textContent=opt.selected?lang.label:(lang.flag?lang.flag+' ':'')+lang.label;
  });
}
