export function mapLanguageCodeToUI(code){
  const base=String(code||'').toLowerCase().split('-')[0];
  return UI_LANGUAGES.some(l=>l.id===base)?base:'';
}
export async function detectPreferredUILanguage(){
  // Priority: browser language first, geo/IP only as fallback
  const langs=[...(navigator.languages||[]),navigator.language].filter(Boolean);
  for(const lang of langs){
    const mapped=mapLanguageCodeToUI(lang);
    if(mapped)return mapped;
  }
  const countryMap=getLanguageSuggestionCountryMap();
  try{
    const rsp=await fetch('/api/geo',{cache:'no-store'});
    if(rsp.ok){
      const geo=await rsp.json().catch(()=>null);
      const country=geo&&geo.country?String(geo.country).toUpperCase():'';
      if(country&&countryMap[country]&&UI_LANGUAGES.some(l=>l.id===countryMap[country]))return countryMap[country];
    }
  }catch(e){}
  return '';
}
export function detectTextLanguage(text){
  const sample=(text||'').toLowerCase().replace(/[^a-zà-öø-ÿа-яёğışöüçñ\s]/g,' ').replace(/\s+/g,' ').slice(0,5000);
  const words=sample.split(' ').filter(w=>w.length>=2);
  if(!words.length)return '';
  const langWords={
    french:new Set(['le','la','les','de','du','des','est','une','un','avec','dans','pour','que','qui','mais','pas','son','sur','elle','vous','nous','mon','ton','tout','cette','être','fait','dit','plus','bien','comme']),
    english:new Set(['the','is','are','and','with','for','that','this','have','was','you','not','but','they','she','his','her','from','been','would','what','will','can','just','more','about','into','than','then']),
    spanish:new Set(['los','las','del','una','con','para','que','por','como','pero','más','esta','ese','son','han','todo','era','tiene','hay','desde','cuando','muy','entre','sobre','también']),
    german:new Set(['der','die','das','und','ist','ein','eine','den','dem','von','mit','auf','für','nicht','sich','auch','des','noch','wie','bei','nach','aus','war','hat','sind','wird','zum','zur','kann','nur']),
    italian:new Set(['che','non','una','per','con','sono','del','della','dei','degli','come','questo','quella','anche','più','suo','sua','suo','era','fatto','molto','quando','dove','ogni','stato','dopo','prima','sempre']),
    portuguese:new Set(['que','não','uma','para','com','como','mais','dos','das','por','seu','sua','mas','isso','este','esta','tem','era','são','quando','muito','também','sobre','pode','depois','onde','bem']),
    arabic:new Set(['من','في','على','إلى','هذا','هذه','كان','لا','ما','أن','عن','مع','هو','هي','ذلك','كل','بعد','قال','لقد','حتى','بين','عند']),
    turkish:new Set(['bir','bu','ile','için','var','olan','den','dan','olarak','gibi','daha','hem','ama','ancak','çok','kadar','sonra','önce','bana','sana','benim','senin','onun']),
    russian:new Set(['что','как','это','был','она','его','для','все','они','при','так','быть','уже','или','мне','нет','еще','бы','себя','тот','только','когда','ему']),
    japanese:new Set(['の','に','は','を','た','が','で','て','と','し','れ','さ','ある','いる','する','から','こと','これ','それ','ない']),
    chinese:new Set(['的','了','在','是','我','他','她','们','这','那','有','你','不','和','就','也','说','要','会','人','到','来','都']),
    korean:new Set(['은','는','이','가','을','를','에','의','로','와','과','도','만','에서','부터','까지','하다','있다','없다']),
    hindi:new Set(['है','का','की','के','में','को','से','ने','पर','और','एक','यह','वह','हैं','था','हम','आप','उन','कि','जो','भी']),
  };
  const scores={};
  for(const[lang,set]of Object.entries(langWords)){
    scores[lang]=words.filter(w=>set.has(w)).length;
  }
  const best=Object.entries(scores).sort((a,b)=>b[1]-a[1])[0];
  if(!best||best[1]<3)return '';
  return best[0];
}
